export type LancamentoStatus = 'PENDENTE' | 'OBSERVACAO' | 'ASSISTIDO' | 'AUTOMATICO' | 'ERRO' | 'CONCLUIDO' | 'IGNORADO';

export type LancamentoModo = 'OBSERVACAO' | 'ASSISTIDO' | 'AUTOMATICO';

export interface LancamentoItem {
    id: string;
    origemId: string; // ID da consolidated_transactions ou hash da transação
    data: string;
    nome: string;
    valor: number;
    igrejaSugerida: string;
    tipoContribuicao?: string;
    status: LancamentoStatus;
    mensagemErro?: string;
    tentativas: number;
    ultimaTentativa?: string;
    metadata?: Record<string, any>;
}

export interface LancamentoState {
    fila: LancamentoItem[];
    modoAtivo: LancamentoModo;
    isProcessando: boolean;
}

import { LancamentoModo, LancamentoStatus } from './types';

export const MODOS_LANCAMENTO = {
    OBSERVACAO: 'OBSERVACAO' as LancamentoModo,
    ASSISTIDO: 'ASSISTIDO' as LancamentoModo,
    AUTOMATICO: 'AUTOMATICO' as LancamentoModo
};

export const STATUS_LANCAMENTO = {
    PENDENTE: 'PENDENTE' as LancamentoStatus,
    OBSERVACAO: 'OBSERVACAO' as LancamentoStatus,
    ASSISTIDO: 'ASSISTIDO' as LancamentoStatus,
    AUTOMATICO: 'AUTOMATICO' as LancamentoStatus,
    ERRO: 'ERRO' as LancamentoStatus,
    CONCLUIDO: 'CONCLUIDO' as LancamentoStatus,
    IGNORADO: 'IGNORADO' as LancamentoStatus
};

export const MODO_LABELS: Record<LancamentoModo, string> = {
    OBSERVACAO: 'Modo Observação (Passivo)',
    ASSISTIDO: 'Modo Assistido (Confirmação)',
    AUTOMATICO: 'Modo Automático (Total)'
};

export const MODO_DESCRIPTIONS: Record<LancamentoModo, string> = {
    OBSERVACAO: 'A IA apenas sugere os lançamentos no log, sem executar ações no sistema externo.',
    ASSISTIDO: 'A IA prepara os lançamentos e aguarda sua confirmação manual antes de processar.',
    AUTOMATICO: 'A IA identifica e lança automaticamente todos os registros reconhecidos com alta confiança.'
};

import { useState, useCallback } from 'react';
import { LancamentoItem, LancamentoModo, LancamentoState } from './types';
import { MODOS_LANCAMENTO, STATUS_LANCAMENTO } from './constants';

export const useLancamentoState = () => {
    const [state, setState] = useState<LancamentoState>({
        fila: [],
        modoAtivo: MODOS_LANCAMENTO.OBSERVACAO,
        isProcessando: false
    });

    const setModoAtivo = useCallback((modo: LancamentoModo) => {
        setState(prev => ({ ...prev, modoAtivo: modo }));
    }, []);

    const setFila = useCallback((novosItens: LancamentoItem[]) => {
        setState(prev => ({ ...prev, fila: novosItens }));
    }, []);

    const atualizarItem = useCallback((id: string, patch: Partial<LancamentoItem>) => {
        setState(prev => ({
            ...prev,
            fila: prev.fila.map(item => 
                item.id === id ? { ...item, ...patch } : item
            )
        }));
    }, []);

    const limparFila = useCallback(() => {
        setState(prev => ({ ...prev, fila: [] }));
    }, []);

    const updateItemStatus = useCallback((id: string, status: LancamentoItem['status'], erro?: string) => {
        atualizarItem(id, { 
            status, 
            mensagemErro: erro, 
            tentativas: state.fila.find(i => i.id === id)?.tentativas || 0 + 1,
            ultimaTentativa: new Date().toISOString() 
        });
    }, [atualizarItem, state.fila]);

    return {
        state,
        setModoAtivo,
        setFila,
        atualizarItem,
        limparFila,
        updateItemStatus
    };
};

import { LancamentoItem } from './types';
import { STATUS_LANCAMENTO } from './constants';

/**
 * SERVIÇO DE LANÇAMENTO AUTOMÁTICO
 * Responsável pelo processamento lógico da fila e mapeamento de dados.
 */
export const lancamentoService = {
    /**
     * Converte registros da Lista Viva (AppContext) para o formato da Fila Interna.
     * Mantém isolamento total não referenciando tipos globais diretamente no mapeamento.
     */
    mapearListaVivaParaFila(listaViva: any[]): LancamentoItem[] {
        if (!Array.isArray(listaViva)) return [];

        return listaViva.map(item => ({
            id: `fila-${item.id || Math.random().toString(36).substr(2, 9)}`,
            origemId: item.id || '',
            data: item.transaction_date || item.date || '',
            nome: item.description || item.nome || 'Sem descrição',
            valor: Number(item.amount || item.valor || 0),
            igrejaSugerida: item.church_name || item.igreja || 'Não identificada',
            tipoContribuicao: item.type || item.tipo,
            status: STATUS_LANCAMENTO.PENDENTE,
            tentativas: 0
        }));
    },

    /**
     * Carrega e filtra dados da Lista Viva para a fila do módulo.
     */
    async carregarDadosDaListaViva(listaViva: any[]): Promise<LancamentoItem[]> {
        console.log("[LancamentoAutomatico] Mapeando registros da Lista Viva para fila interna...");
        return this.mapearListaVivaParaFila(listaViva);
    },

    /**
     * Registra o resultado local de um processamento.
     */
    async registrarResultado(id: string, resultado: any): Promise<boolean> {
        console.log(`[LancamentoAutomatico] Resultado registrado para o item ${id}:`, resultado);
        return true;
    },

    /**
     * Stub para atualização de status lógico.
     */
    async atualizarStatus(id: string, status: LancamentoItem['status']): Promise<void> {
        console.log(`[LancamentoAutomatico] Mudança de status solicitada: ${id} -> ${status}`);
    }
};

